    elif suffix in RESOURCE_BUILD_EXTENSIONS or suffix in FOLDER_TYPE_MAP:
        _ensure_build_file(objects, resource_phase_files, file_ref_id)


def _normalize_image_key(path: Path) -> str:
    return IMAGE_SCALE_SUFFIX_RE.sub("", path.stem)


def _build_resource_index(search_root: Path) -> tuple[dict[str, list[Path]], dict[str, list[Path]]]:
    exact_index: dict[str, list[Path]] = {}
    image_index: dict[str, list[Path]] = {}
    for path in iter_project_files(search_root):
        suffix = path.suffix.lower()
        if suffix not in RESOURCE_SEARCH_EXTENSIONS:
            continue
        exact_index.setdefault(path.name, []).append(path)
        if suffix in {".png", ".jpg", ".jpeg", ".pdf"}:
            image_index.setdefault(_normalize_image_key(path), []).append(path)
    return exact_index, image_index


def _extract_resource_names(source_files: list[Path]) -> set[str]:
    resource_names: set[str] = set()
    for path in source_files:
        if not is_text_file(path):
            continue
        content = path.read_text(encoding="utf-8", errors="ignore")
        for name in IMAGE_NAMED_RE.findall(content):
            if name and name.startswith("A_"):
                resource_names.add(name)
        for name, ext in URL_RESOURCE_RE.findall(content):
            if name and ext:
                resource_names.add(f"{name}.{ext}")
        for literal_name in RESOURCE_LITERAL_RE.findall(content):
            if literal_name:
                resource_names.add(literal_name)
    return resource_names


def _resource_matches(resource_name: str, exact_index: dict[str, list[Path]], image_index: dict[str, list[Path]]) -> list[Path]:
    if "." in resource_name:
        return sorted(exact_index.get(resource_name, []))
    return sorted(image_index.get(resource_name, []))


def _resource_dest_parts(feature_name: str, preset: dict | None, candidate: Path, resource_name: str) -> tuple[str, str]:
    tab = (preset or {}).get("tab") or {}
    image_name = str(tab.get("image_name") or "")
    if image_name and (resource_name == image_name or resource_name.startswith(image_name + "-")):
        return "Resource", "Main"

    resource_group = str((preset or {}).get("resource_group") or "")
    if resource_group:
        return "Resource", resource_group

    if "Resource" in candidate.parts:
        resource_index = candidate.parts.index("Resource")
        if len(candidate.parts) > resource_index + 1:
