}

IMAGE_SCALE_SUFFIX_RE = re.compile(r"@(?:2|3)x$")
RESOURCE_LITERAL_RE = re.compile(r'@\"([^\"]+\.(?:png|jpg|jpeg|mp3|wav|json|plist|pdf|strings|txt))\"')
IMAGE_NAMED_RE = re.compile(r'imageNamed:\s*@\"([^\"]+)\"')
URL_RESOURCE_RE = re.compile(r'URLForResource:\s*@\"([^\"]+)\"\s+withExtension:\s*@\"([^\"]+)\"')


def _load_pbxproj_json(pbxproj_path: Path) -> dict:
    completed = subprocess.run(
        ["plutil", "-convert", "json", "-o", "-", str(pbxproj_path)],
        capture_output=True,
        text=True,
        check=True,
    )
    return json.loads(completed.stdout)


def _write_pbxproj_xml(pbxproj_path: Path, payload: dict) -> None:
    with pbxproj_path.open("wb") as handle:
        plistlib.dump(payload, handle, sort_keys=False)


def _generate_id(objects: dict) -> str:
    while True:
        candidate = uuid.uuid4().hex.upper()[:24]
        if candidate not in objects:
            return candidate


def _find_object_id(objects: dict, isa: str, **attrs: str) -> str:
    for object_id, value in objects.items():
        if value.get("isa") != isa:
            continue
        if all(value.get(key) == expected for key, expected in attrs.items()):
            return object_id
    raise KeyError(f"找不到对象: isa={isa}, attrs={attrs}")


def _find_child_group(objects: dict, parent_group_id: str, name: str) -> str | None:
    parent = objects[parent_group_id]
    for child_id in parent.get("children", []):
        child = objects.get(child_id)
        if not child or child.get("isa") != "PBXGroup":
            continue
        if child.get("path") == name or child.get("name") == name:
            return child_id
    return None


def _find_child_file_ref(objects: dict, parent_group_id: str, name: str) -> str | None:
    parent = objects[parent_group_id]
    for child_id in parent.get("children", []):
        child = objects.get(child_id)
        if not child or child.get("isa") != "PBXFileReference":
            continue
        if child.get("path") == name or child.get("name") == name:
            return child_id
    return None


def _ensure_group(objects: dict, app_group_id: str, group_parts: list[str]) -> str:
    current_group_id = app_group_id
    for part in group_parts:
        existing_group_id = _find_child_group(objects, current_group_id, part)
        if existing_group_id:
            current_group_id = existing_group_id
            continue

        group_id = _generate_id(objects)
        objects[group_id] = {
            "isa": "PBXGroup",
            "children": [],
            "path": part,
            "sourceTree": "<group>",
        }
        objects[current_group_id].setdefault("children", []).append(group_id)
        current_group_id = group_id
    return current_group_id


def _file_reference_payload(filename: str) -> dict:
    suffix = Path(filename).suffix.lower()
    if suffix in FOLDER_TYPE_MAP:
        return {
            "isa": "PBXFileReference",
            "lastKnownFileType": FOLDER_TYPE_MAP[suffix],
            "path": filename,
            "sourceTree": "<group>",
        }
    return {
        "isa": "PBXFileReference",
        "lastKnownFileType": FILE_TYPE_MAP.get(suffix, "text"),
        "path": filename,
        "sourceTree": "<group>",
    }


def _ensure_build_file(objects: dict, build_phase_files: list[str], file_ref_id: str) -> str:
    for build_file_id in build_phase_files:
        build_file = objects.get(build_file_id)
        if build_file and build_file.get("fileRef") == file_ref_id:
            return build_file_id

    build_file_id = _generate_id(objects)
    objects[build_file_id] = {
        "isa": "PBXBuildFile",
        "fileRef": file_ref_id,
    }
    build_phase_files.append(build_file_id)
    return build_file_id


def _replace_tokens(value: str, rename_map: dict[str, str]) -> str:
    updated = value
    for old, new in rename_map.items():
        updated = updated.replace(old, new)
    return updated


def _collect_source_files(source_root: Path) -> list[Path]:
    if source_root.is_dir():
        return [
            path
            for path in sorted(source_root.rglob("*"))
            if path.is_file() and not should_ignore_file(path)
        ]
    if source_root.is_file() and not should_ignore_file(source_root):
        return [source_root]

    parent = source_root.parent
    if not parent.is_dir():
        return []

    return [
        path
        for path in sorted(parent.glob(source_root.name + ".*"))
        if path.is_file() and not should_ignore_file(path)
    ]


def _copy_source(source_root: Path, dest_dir: Path, rename_map: dict[str, str]) -> list[Path]:
    copied_files: list[Path] = []
    source_files = _collect_source_files(source_root)
    for source_path in source_files:
        if source_root.is_dir():
            relative_path = source_path.relative_to(source_root)
        else:
            relative_path = Path(source_path.name)

        renamed_parts = [_replace_tokens(part, rename_map) for part in relative_path.parts]
        target_path = dest_dir.joinpath(*renamed_parts)
        target_path.parent.mkdir(parents=True, exist_ok=True)

        if is_text_file(source_path):
            content = source_path.read_text(encoding="utf-8", errors="ignore")
            target_path.write_text(_replace_tokens(content, rename_map), encoding="utf-8")
        else:
            shutil.copy2(source_path, target_path)

        copied_files.append(target_path)
    return copied_files


def _register_file(
