def _extract_resource_names(source_files: list[Path]) -> set[str]:
    resource_names: set[str] = set()
    for path in source_files:
        if not is_text_file(path):
            continue
        content = path.read_text(encoding="utf-8", errors="ignore")
        for name in IMAGE_NAMED_RE.findall(content):
            if name and name.startswith("A_"):
                resource_names.add(name)
        for name, ext in URL_RESOURCE_RE.findall(content):
            if name and ext:
                resource_names.add(f"{name}.{ext}")
        for literal_name in RESOURCE_LITERAL_RE.findall(content):
            if literal_name:
                resource_names.add(literal_name)
    return resource_names


