#pragma mark - 屏幕方向控制

// 交换demoAppDelegate的方向控制方法
- (void)swizzleDemoAppDelegateOrientationMethod {
    Class targetClass = NSClassFromString(@"demoAppDelegate");
    SEL originalSelector = @selector(application:supportedInterfaceOrientationsForWindow:);
    SEL swizzledSelector = @selector(swizzled_application:supportedInterfaceOrientationsForWindow:);

    Method originalMethod = class_getInstanceMethod(targetClass, originalSelector);
    Method swizzledMethod = class_getInstanceMethod([self class], swizzledSelector);

    if (originalMethod && swizzledMethod) {
        method_exchangeImplementations(originalMethod, swizzledMethod);
    }
}

// 新的屏幕方向控制方法
- (UIInterfaceOrientationMask)swizzled_application:(UIApplication *)application
                        supportedInterfaceOrientationsForWindow:(UIWindow *)window {
        return UIInterfaceOrientationMaskAll;
}

#pragma mark - Setup UI

- (void)setupTopBar {
    CGFloat barHeight = ZOOM(44);
    CGFloat screenWidth = UIScreen.mainScreen.bounds.size.width;

    // 初始暂时放在顶部（后续 layout 时会修正安全区）
    self.topBar = [[UIView alloc] initWithFrame:CGRectMake(0, 0, screenWidth, barHeight)];
    self.topBar.backgroundColor = CLEAR_COLOR;
//    self.topBar.layer.shadowColor = [UIColor colorWithWhite:0 alpha:0.2].CGColor;
//    self.topBar.layer.shadowOpacity = 0.3;
//    self.topBar.layer.shadowOffset = CGSizeMake(0, 1);
    [self.view addSubview:self.topBar];

    CGFloat btnWidth = ZOOM(98);
    NSMutableArray *btns = [NSMutableArray array];

    for (int i = 0; i < self.images.count; i++) {
        UIButton *btn = [UIButton buttonWithType:UIButtonTypeCustom];
        if (i == 0) {
            btn.frame = CGRectMake(ZOOM(12), 0, ZOOM(100), ZOOM(44));
        } else if (i == 1) {
            btn.frame = CGRectMake(ZOOM(120), 0, ZOOM(100), ZOOM(44));
        } else {
            btn.frame = CGRectMake(ZOOM(228), 0, ZOOM(100), ZOOM(44));
        }
//        [btn setTitle:titles[i] forState:UIControlStateNormal];
        [btn setBackgroundImage:[UIImage imageNamed:self.images[i]] forState:UIControlStateNormal];
        [btn setBackgroundImage:[UIImage imageNamed:[self.images[i] stringByAppendingString:@"-Selected"]] forState:UIControlStateSelected];
        btn.layer.cornerRadius = ZOOM(17);
        btn.tag = 100 + i;
        [btn addTarget:self action:@selector(tabClicked:) forControlEvents:UIControlEventTouchUpInside];
        [self.topBar addSubview:btn];
        [btns addObject:btn];
        if (i == 0){
            btn.selected = YES;
//            btn.backgroundColor = DEEP_COLOR;
        }
    }

    self.tabButtons = btns;

//    UIView *line = [[UIView alloc] initWithFrame:CGRectMake(0, barHeight - 1, screenWidth, 1)];
//    line.backgroundColor = [UIColor lightGrayColor];
//    [self.topBar addSubview:line];

    self.soundButton = [[UIButton alloc] init];
//    self.soundButton.hidden = YES;
    [_soundButton setBackgroundImage:[UIImage imageNamed:@"A_Sound_Open"] forState:UIControlStateNormal];
    [_soundButton addTarget:self action:@selector(soundChange:) forControlEvents:UIControlEventTouchUpInside];
    [self.topBar addSubview:_soundButton];
    [_soundButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.topBar).offset(ZOOM(5));
        make.right.equalTo(self.topBar).offset(ZOOM(-12));
        make.height.width.mas_equalTo(ZOOM(24));
    }];
}

- (void)setupChildViewControllers {
    AiTalkViewController *vc1 = [AiTalkViewController new];
    VoiceChangeViewController *vc2 = [VoiceChangeViewController new];
    ColorSensitivityGameViewController *vc3 = [ColorSensitivityGameViewController new];

    self.controllers = @[vc1, vc2, vc3];

    [self displayChildVC:vc1];
}

#pragma mark - Tab Action

- (void)soundChange:(UIButton *)sender {

//    BOOL isTestVC = [self.currentVC isKindOfClass:[TestViewController class]];

    if (_isSilence) {
//        if (isTestVC) {
//            [_soundButton setBackgroundImage:[UIImage imageNamed:@"A_Sound_Dark_Open"] forState:UIControlStateNormal];
//        } else {
            [_soundButton setBackgroundImage:[UIImage imageNamed:@"A_Sound_Open"] forState:UIControlStateNormal];
//        }
        [[SpeechManager shared] sound];
        _isSilence = NO;
    } else {
//        if (isTestVC) {
//            [_soundButton setBackgroundImage:[UIImage imageNamed:@"A_Sound_Dark_Close"] forState:UIControlStateNormal];
//        } else {
            [_soundButton setBackgroundImage:[UIImage imageNamed:@"A_Sound_Close"] forState:UIControlStateNormal];
//        }
        [[SpeechManager shared] silence];
        _isSilence = YES;
    }

}

- (void)tabClicked:(UIButton *)sender {

    for (UIButton *btn in self.tabButtons) {
        btn.selected = (btn == sender);
    }

    NSInteger index = sender.tag - 100;
    if (index < self.controllers.count) {
        [self displayChildVC:self.controllers[index]];
        for (int i = 0; i < self.tabButtons.count; i++) {
            self.soundButton.hidden = NO;
            [_tabButtons[i] setBackgroundImage:[UIImage imageNamed:self.images[i]] forState:UIControlStateNormal];
            [_tabButtons[i] setBackgroundImage:[UIImage imageNamed:[self.images[i] stringByAppendingString:@"-Selected"]] forState:UIControlStateSelected];
        }

    }
}

#pragma mark - Child View Controller Switching

- (void)displayChildVC:(UIViewController *)vc {
    if (self.currentVC) {
        [self.currentVC willMoveToParentViewController:nil];
        [self.currentVC.view removeFromSuperview];
        [self.currentVC removeFromParentViewController];
    }

    [self addChildViewController:vc];

//    CGFloat topOffset = CGRectGetMaxY(self.topBar.frame);
    CGFloat safeBottom = 0;
    if (@available(iOS 11.0, *)) {
        safeBottom = self.view.safeAreaInsets.bottom;
    }

    vc.view.frame = CGRectMake(0,
                               0,
                               self.view.bounds.size.width,
                               self.view.bounds.size.height);

    vc.view.autoresizingMask = UIViewAutoresizingFlexibleWidth | UIViewAutoresizingFlexibleHeight;
    [self.view addSubview:vc.view];
    [vc didMoveToParentViewController:self];

    [self.view bringSubviewToFront:self.topBar];
    self.currentVC = vc;
}

#pragma mark - Layout Fix (关键补充)

- (void)viewDidLayoutSubviews {
    [super viewDidLayoutSubviews];

    // 重新修正 topBar 避免被刘海挡住
    CGFloat safeTop = 0;
    if (@available(iOS 11.0, *)) {
        safeTop = self.view.safeAreaInsets.top;
    }
    CGRect frame = self.topBar.frame;
    frame.origin.y = safeTop;
    self.topBar.frame = frame;

