- (void)playRecordedAudio {
    if (!self.recordFileURL) return;

    if (!self.isPlaying) {
        // Rebuild engine before each playback to switch effects
        [self setupEngineForCurrentEffect];

        // Re-schedule (includes playback completion callback)
        [self scheduleAudioFileForPlayback];

        // ▶️ Start playback
        [self.playerNode play];
        self.isPlaying = YES;
        [self updatePlayButtonToPauseIcon];

    } else {
        // ⏸ Pause
        [self.playerNode pause];
        self.isPlaying = NO;
        [self updatePlayButtonToPlayIcon];
    }
}

- (void)setupEngineForCurrentEffect {
    self.engine = [[AVAudioEngine alloc] init];
    self.playerNode = [[AVAudioPlayerNode alloc] init];
    self.pitchNode = [[AVAudioUnitTimePitch alloc] init];
    AVAudioUnitReverb *reverb = [[AVAudioUnitReverb alloc] init];

    // Reset default parameters
    self.pitchNode.pitch = 0;
    self.pitchNode.rate = 1.0;
    reverb.wetDryMix = 0;

    // Set according to current selected effect
    if ([self.selectedEffect isEqualToString:@"chipmunk"]) {
        self.pitchNode.pitch = 1000;
        self.pitchNode.rate = 1.2;
    } else if ([self.selectedEffect isEqualToString:@"deep"]) {
        self.pitchNode.pitch = -800;
        self.pitchNode.rate = 0.9;
    } else if ([self.selectedEffect isEqualToString:@"robot"]) {
        self.pitchNode.overlap = 8.0;
    } else if ([self.selectedEffect isEqualToString:@"girl"]) {
        self.pitchNode.pitch = 800;  // 适当提高音调模拟女声
        self.pitchNode.rate = 1.1;   // 稍微加快语速
        // 可以保留一些混响效果让声音更自然
        reverb.wetDryMix = 30;       // 降低混响强度
    }

    // Connect nodes
    [self.engine attachNode:self.playerNode];
    [self.engine attachNode:self.pitchNode];
    [self.engine attachNode:reverb];
    [self.engine connect:self.playerNode to:self.pitchNode format:nil];
