    NSLog(@"Banner ad loaded successfully");
    // Add ad to view after successful loading
    [self.view addSubview:bannerAdView];

    // Set ad view position and size
    bannerAdView.translatesAutoresizingMaskIntoConstraints = NO;

    // Left alignment
    NSLayoutConstraint *leftConstraint = [NSLayoutConstraint constraintWithItem:bannerAdView
                                                                       attribute:NSLayoutAttributeLeft
                                                                       relatedBy:NSLayoutRelationEqual
                                                                          toItem:self.view
                                                                       attribute:NSLayoutAttributeLeft
                                                                      multiplier:1.0
                                                                        constant:0];
    // Right alignment
    NSLayoutConstraint *rightConstraint = [NSLayoutConstraint constraintWithItem:bannerAdView
                                                                       attribute:NSLayoutAttributeRight
                                                                       relatedBy:NSLayoutRelationEqual
                                                                          toItem:self.view
                                                                       attribute:NSLayoutAttributeRight
                                                                      multiplier:1.0
                                                                        constant:0];
    // Bottom alignment
    NSLayoutConstraint *topConstraint = [NSLayoutConstraint constraintWithItem:bannerAdView
                                                                       attribute:NSLayoutAttributeTop
                                                                       relatedBy:NSLayoutRelationEqual
                                                                          toItem:self.view.safeAreaLayoutGuide
                                                                       attribute:NSLayoutAttributeBottom
                                                                      multiplier:1.0
                                                                        constant:-(self.bannerAdHeight + ZOOM(2))];
    // Height constraint
    NSLayoutConstraint *heightConstraint = [NSLayoutConstraint constraintWithItem:bannerAdView
                                                                         attribute:NSLayoutAttributeHeight
                                                                         relatedBy:NSLayoutRelationEqual
                                                                            toItem:nil
                                                                         attribute:NSLayoutAttributeNotAnAttribute
                                                                        multiplier:1.0
                                                                          constant:self.bannerAdHeight];

    // Add constraints
    [self.view addConstraints:@[leftConstraint, rightConstraint, topConstraint, heightConstraint]];
}

