@end


@implementation AIChatListViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = BACKGROUND_COLOR;
#if ENABLE_ADS
        /******** Feature A Ad Logic *********/
        self.bannerAdHeight = ZOOM(75);
#endif
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];

//    self.title = @"Multi Chat";
    self.view.backgroundColor = BACKGROUND_COLOR;

//    self.navigationItem.leftBarButtonItem = self.functionBarItem;
    self.navigationItem.rightBarButtonItem = self.addChatBarItem;

    [AIChatListStorage ensureDefaultChatsExist];
    self.chatItems = [AIChatListStorage loadChatList];

    [self setupUI];
    [self.collectionView reloadData];
}

#if ENABLE_ADS
/******** Feature A Ad Logic *********/
- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [self groMoreBannerAdLoad]; // Load banner ad
}
#endif

#pragma mark - UI

- (void)setupUI {
    [self.view addSubview:self.collectionView];

    [self.collectionView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.view);
    }];
}

#pragma mark - UICollectionView DataSource

- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.chatItems.count;
}

- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {

    AIChatListCardCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"AIChatListCardCell" forIndexPath:indexPath];

    AIChatListItemModel *item = self.chatItems[indexPath.item];
    NSString *absPath = [AIChatListStorage avatarPathForChatId:item.chatId];
    UIImage *img = [UIImage imageWithContentsOfFile:absPath];
    [cell configWithTitle:item.title subtitle:item.subtitle image:img? img: [UIImage imageNamed:item.icon]];

    return cell;
}

#pragma mark - UICollectionView Delegate

- (void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath {
    AIChatListItemModel *item = self.chatItems[indexPath.item];

    AIChatConversationViewController *vc = [[AIChatConversationViewController alloc] init];
    vc.chatId = item.chatId;
    vc.title = item.title;
    vc.modalPresentationStyle = UIModalPresentationFullScreen;
//    [self.navigationController pushViewController:vc animated:YES];
    [self presentViewController:vc animated:YES completion:nil];
}

- (CGSize)collectionView:(UICollectionView *)collectionView
                  layout:(UICollectionViewLayout *)collectionViewLayout
          sizeForItemAtIndexPath:(NSIndexPath *)indexPath {

    return CGSizeMake(ZOOMW(343), ZOOMW(74)); // 高度会被压缩到实际需要的大小
}

#pragma mark - Add Chat

- (void)addChat {
    AIChatListAddViewController *addVC = [[AIChatListAddViewController alloc] init];

    __weak typeof(self) weakSelf = self;

    addVC.onConfirm = ^(NSString *title, UIImage *_Nullable avatarImage) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;

        AIChatListItemModel *item = [[AIChatListItemModel alloc] init];
        item.chatId = [[NSUUID UUID] UUIDString];
        item.title = title.length ? title : @"Good Friend";
        item.subtitle = @"Are you going to watch a movie after work tonight?";

    return _collectionView;
}


