#if ENABLE_ADS

/******** Feature A Ad Logic *********/
#pragma mark - GroMore BannerAd

/******** Banner Ad Configuration *********/
- (void)groMoreBannerAdLoad {
    // Remove previous ad
    [self.bannerAdView removeFromSuperview];

    // Reconfigure and load ad
    CGFloat bannerHeight = self.bannerAdHeight;
    CGFloat bannerWidth = [UIScreen mainScreen].bounds.size.width;
    CGSize adSize = CGSizeMake(bannerWidth, bannerHeight);
    BUAdSlot *slot = [[BUAdSlot alloc] init];
    slot.ID = [AdManager sharedManager].adModel.bannerSlotId;
    BUNativeExpressBannerView *bannerView = [[BUNativeExpressBannerView alloc] initWithSlot:slot rootViewController:self adSize:adSize];
    bannerView.delegate = self;
    self.bannerAdView = bannerView;
    [self.bannerAdView loadAdData];
}

#pragma mark - BUMNativeExpressBannerViewDelegate

/******** Banner Ad Callback Handling *********/

// Ad loaded successfully
- (void)nativeExpressBannerAdViewDidLoad:(BUNativeExpressBannerView *)bannerAdView {
    NSLog(@"Banner ad loaded successfully");
    // Add ad to view after successful loading
    [self.view addSubview:bannerAdView];

    // Set ad view position and size
    bannerAdView.translatesAutoresizingMaskIntoConstraints = NO;

    // Left alignment
    NSLayoutConstraint *leftConstraint = [NSLayoutConstraint constraintWithItem:bannerAdView
                                                                       attribute:NSLayoutAttributeLeft
                                                                       relatedBy:NSLayoutRelationEqual
                                                                          toItem:self.view
                                                                       attribute:NSLayoutAttributeLeft
                                                                      multiplier:1.0
                                                                        constant:0];
    // Right alignment
    NSLayoutConstraint *rightConstraint = [NSLayoutConstraint constraintWithItem:bannerAdView
                                                                       attribute:NSLayoutAttributeRight
                                                                       relatedBy:NSLayoutRelationEqual
                                                                          toItem:self.view
                                                                       attribute:NSLayoutAttributeRight
                                                                      multiplier:1.0
                                                                        constant:0];
    // Bottom alignment
    NSLayoutConstraint *topConstraint = [NSLayoutConstraint constraintWithItem:bannerAdView
                                                                       attribute:NSLayoutAttributeTop
                                                                       relatedBy:NSLayoutRelationEqual
                                                                          toItem:self.view.safeAreaLayoutGuide
                                                                       attribute:NSLayoutAttributeBottom
                                                                      multiplier:1.0
                                                                        constant:-(self.bannerAdHeight + ZOOM(2))];
    // Height constraint
    NSLayoutConstraint *heightConstraint = [NSLayoutConstraint constraintWithItem:bannerAdView
                                                                         attribute:NSLayoutAttributeHeight
                                                                         relatedBy:NSLayoutRelationEqual
                                                                            toItem:nil
                                                                         attribute:NSLayoutAttributeNotAnAttribute
                                                                        multiplier:1.0
                                                                          constant:self.bannerAdHeight];

    // Add constraints
    [self.view addConstraints:@[leftConstraint, rightConstraint, topConstraint, heightConstraint]];
}

// Ad load failed
- (void)nativeExpressBannerAdView:(BUNativeExpressBannerView *)bannerAdView didLoadFailWithError:(NSError *)error {
    NSLog(@"Banner ad load failed: %@", error.localizedDescription);
