- (void)useHint {
    if (self.hintsRemaining <= 0 || !self.gameActive) return;

    self.hintsRemaining--;
    [self updateDisplay];

    // Flash the correct answer
    UIView *correctTile = [self.colorGridContainer viewWithTag:self.correctPosition + 100];
    [UIView animateWithDuration:0.3 animations:^{
        correctTile.alpha = 0.3;
    } completion:^(BOOL finished) {
        [UIView animateWithDuration:0.3 animations:^{
            correctTile.alpha = 1.0;
        } completion:^(BOOL finished) {
            [UIView animateWithDuration:0.3 animations:^{
