#pragma mark - Game Logic

- (void)startGame {
    self.score = 0;
    self.difficulty = 1;
    self.timeElapsed = 0;
    self.totalTime = 60;
    self.hintsRemaining = 3;
    self.totalAttempts = 0;
    self.correctAttempts = 0;
    self.gameActive = YES;

    // Reset difference explanation view visibility
    self.differenceExplanation.hidden = NO;

    // Hide start screen, show game screen
    self.startScreen.hidden = YES;
    self.startButton.hidden = YES;
    self.gameScreen.hidden = NO;
    self.resultScreen.hidden = YES;
    self.playAgainButton.hidden = YES;

    // Ensure view layout is updated
    [self.view setNeedsLayout];
    [self.view layoutIfNeeded];

    [self updateDisplay];
    [self generateColorGrid];

    // Start timer
    self.gameTimer = [NSTimer scheduledTimerWithTimeInterval:1.0 target:self selector:@selector(updateTimer) userInfo:nil repeats:YES];
}

- (void)restartGame {
    [self.gameTimer invalidate];
    [self startGame];
}

- (void)endGame {
    self.gameActive = NO;
    [self.gameTimer invalidate];

    // Calculate accuracy
    CGFloat accuracy = (self.totalAttempts > 0) ? (CGFloat)self.correctAttempts / self.totalAttempts * 100 : 0;

    // Update result screen
    self.finalScoreLabel.text = [NSString stringWithFormat:@"Score：%ld", (long)self.score];
    self.finalTimeLabel.text = [NSString stringWithFormat:@"Time：%@", [self formatTime:self.timeElapsed]];
    self.finalDifficultyLabel.text = [NSString stringWithFormat:@"Level：%ld", (long)self.difficulty];
    self.accuracyLabel.text = [NSString stringWithFormat:@"Accuracy：%.1f%%", accuracy];

    // Show result screen
    self.gameScreen.hidden = YES;
    self.resultScreen.hidden = NO;
    self.playAgainButton.hidden = NO;
}

- (void)useHint {
    if (self.hintsRemaining <= 0 || !self.gameActive) return;

    self.hintsRemaining--;
    [self updateDisplay];

    // Flash the correct answer
    UIView *correctTile = [self.colorGridContainer viewWithTag:self.correctPosition + 100];
    [UIView animateWithDuration:0.3 animations:^{
        correctTile.alpha = 0.3;
    } completion:^(BOOL finished) {
        [UIView animateWithDuration:0.3 animations:^{
            correctTile.alpha = 1.0;
        } completion:^(BOOL finished) {
            [UIView animateWithDuration:0.3 animations:^{
                correctTile.alpha = 0.3;
            } completion:^(BOOL finished) {
                [UIView animateWithDuration:0.3 animations:^{
                    correctTile.alpha = 1.0;
                }];
            }];
        }];
    }];
}

- (void)generateColorGrid {
    // Clear old tiles
    for (UIView *subview in self.colorGridContainer.subviews) {
        [subview removeFromSuperview];
    }

    // Generate random color
    self.originalColor = [UIColor randomColor];

    // Generate slightly different color
    NSInteger channelChanged;
    NSInteger amountChanged;
    self.differentColor = [UIColor colorDifferentFromColor:self.originalColor
                                           withDifficulty:self.difficulty
                                           channelChanged:&channelChanged
                                             amountChanged:&amountChanged];

    // Randomly select correct position
    self.correctPosition = arc4random_uniform(16); // 4x4 grid

    // Update difference explanation
    [self updateDifferenceExplanationWithChannel:channelChanged amount:amountChanged];

    // Create 4x4 grid
    CGFloat tileSize = (self.colorGridContainer.frame.size.width - 30) / 4;
    for (int i = 0; i < 16; i++) {
        UIColor *tileColor = (i == self.correctPosition) ? self.differentColor : self.originalColor;

        UIView *tile = [[UIView alloc] initWithFrame:CGRectMake(
            (i % 4) * (tileSize + 10),
            (i / 4) * (tileSize + 10),
            tileSize,
            tileSize
        )];
        tile.backgroundColor = tileColor;
        tile.layer.cornerRadius = 8;
        tile.tag = i + 100; // For identification

        // Add tap gesture
        UITapGestureRecognizer *tap = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(tileTapped:)];
        [tile addGestureRecognizer:tap];
        tile.userInteractionEnabled = YES;

        [self.colorGridContainer addSubview:tile];
    }
}

- (void)tileTapped:(UITapGestureRecognizer *)gesture {
    if (!self.gameActive) return;

