#import <Foundation/Foundation.h>

NS_ASSUME_NONNULL_BEGIN

// 颜色扩展 - 用于生成随机颜色
@interface UIColor (ColorSensitivityGame)

+ (UIColor *)randomColor;
+ (UIColor *)colorDifferentFromColor:(UIColor *)originalColor withDifficulty:(NSInteger)difficulty channelChanged:(NSInteger *_Nullable)channel amountChanged:(NSInteger *_Nullable)amount;

@end

NS_ASSUME_NONNULL_END

//
//  UIColor+ColorSensitivityGame.m
//  Calculator
//
//  Created by 蒙俊竹 on 2025/9/19.
//

#import "UIColor+ColorSensitivityGame.h"

@implementation UIColor (ColorSensitivityGame)

// 生成随机颜色
+ (UIColor *)randomColor {
    CGFloat red = arc4random_uniform(256) / 255.0;
    CGFloat green = arc4random_uniform(256) / 255.0;
    CGFloat blue = arc4random_uniform(256) / 255.0;
    return [UIColor colorWithRed:red green:green blue:blue alpha:1.0];
}

// 生成与原颜色略有不同的颜色
+ (UIColor *)colorDifferentFromColor:(UIColor *)originalColor withDifficulty:(NSInteger)difficulty channelChanged:(NSInteger *)channel amountChanged:(NSInteger *)amount {
    // 提取RGB成分
    CGFloat red, green, blue, alpha;
    [originalColor getRed:&red green:&green blue:&blue alpha:&alpha];

    // 将 0-1 范围的 RGB 转换为 0-255
    NSInteger r = red * 255;
    NSInteger g = green * 255;
    NSInteger b = blue * 255;

    // 根据难度调整差异大小
    NSInteger maxDiff = 35 - (difficulty * difficulty * 0.05);
    NSInteger minDiff = 5 + (difficulty * 0.5);
    NSInteger clampedMaxDiff = MAX(minDiff + 1, MIN(35, maxDiff));

    // 随机选择一个通道进行修改
    NSInteger selectedChannel = arc4random_uniform(3);
    NSInteger range = clampedMaxDiff - minDiff + 1;
    NSInteger diff = (NSInteger)arc4random_uniform((uint32_t)range) + minDiff;

    // 随机决定是增加还是减少
    if (arc4random_uniform(2) > 0) {
        diff = -diff;
    }

    // 创建新的颜色
    NSInteger newR = r;
    NSInteger newG = g;
    NSInteger newB = b;

    switch (selectedChannel) {
        case 0: newR = MAX(0, MIN(255, r + diff)); break;
        case 1: newG = MAX(0, MIN(255, g + diff)); break;
        case 2: newB = MAX(0, MIN(255, b + diff)); break;
    }

    if (channel) *channel = selectedChannel;
    if (amount) *amount = diff;

    return [UIColor colorWithRed:newR/255.0 green:newG/255.0 blue:newB/255.0 alpha:1.0];
}

@end

